import React, { useState, useEffect } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, 
  ResponsiveContainer, Cell, PieChart, Pie 
} from 'recharts';
import { InventoryItem, UsageLog } from '../types';
import { geminiService } from '../services/geminiService';

interface DashboardProps {
  inventory: InventoryItem[];
  usageLogs: UsageLog[];
}

const Dashboard: React.FC<DashboardProps> = ({ inventory, usageLogs }) => {
  const [insights, setInsights] = useState<string>('Generating AI insights...');
  const [loadingInsights, setLoadingInsights] = useState(true);

  useEffect(() => {
    const fetchInsights = async () => {
      setLoadingInsights(true);
      const result = await geminiService.getInventoryInsights(inventory);
      setInsights(result || "No insights available.");
      setLoadingInsights(false);
    };
    fetchInsights();
  }, [inventory]);

  const chartData = inventory.map(item => ({
    name: item.bloodType,
    ml: item.quantityMl,
    threshold: item.thresholdMl,
    isLow: item.quantityMl < item.thresholdMl,
  }));

  const pieData = inventory.map(item => ({
    name: item.bloodType,
    value: item.quantityMl,
  }));

  const COLORS = ['#ef4444', '#f87171', '#3b82f6', '#60a5fa', '#10b981', '#34d399', '#f59e0b', '#fbbf24'];

  const totalStock = inventory.reduce((acc, curr) => acc + curr.quantityMl, 0);
  const lowStockCount = inventory.filter(i => i.quantityMl < i.thresholdMl).length;

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <p className="text-sm font-medium text-slate-500 mb-1">Total Inventory</p>
          <p className="text-3xl font-bold text-slate-900">{(totalStock / 1000).toFixed(1)}L</p>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <p className="text-sm font-medium text-slate-500 mb-1">Low Stock Alerts</p>
          <p className={`text-3xl font-bold ${lowStockCount > 0 ? 'text-red-500' : 'text-emerald-500'}`}>
            {lowStockCount}
          </p>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <p className="text-sm font-medium text-slate-500 mb-1">Usage Today</p>
          <p className="text-3xl font-bold text-slate-900">
            {usageLogs.filter(log => log.usageDate.includes(new Date().toISOString().split('T')[0])).reduce((a, b) => a + b.quantityMl, 0)}ml
          </p>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <p className="text-sm font-medium text-slate-500 mb-1">Active Donors</p>
          <p className="text-3xl font-bold text-slate-900">10</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-slate-200 h-[400px]">
          <h3 className="font-bold text-slate-800 mb-6">Stock Levels by Blood Type (ml)</h3>
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
              <XAxis dataKey="name" />
              <YAxis />
              <Tooltip 
                cursor={{ fill: '#f8fafc' }}
                contentStyle={{ borderRadius: '8px', border: '1px solid #e2e8f0' }}
              />
              <Bar dataKey="ml" name="Available ml">
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.isLow ? '#ef4444' : '#3b82f6'} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex flex-col h-[400px]">
          <h3 className="font-bold text-slate-800 mb-6">Distribution</h3>
          <ResponsiveContainer width="100%" height="80%">
            <PieChart>
              <Pie
                data={pieData}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={80}
                paddingAngle={5}
                dataKey="value"
              >
                {pieData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
          <div className="mt-auto grid grid-cols-2 gap-2">
            {inventory.slice(0, 4).map((item, idx) => (
              <div key={item.bloodType} className="flex items-center gap-2 text-xs">
                <div className="w-3 h-3 rounded-full" style={{ backgroundColor: COLORS[idx] }}></div>
                <span className="font-medium">{item.bloodType}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="bg-gradient-to-br from-indigo-900 to-slate-900 p-8 rounded-xl shadow-lg text-white">
        <div className="flex items-center gap-3 mb-4">
          <i className="fa-solid fa-wand-magic-sparkles text-indigo-400 text-2xl"></i>
          <h3 className="text-xl font-bold">AI Stock Insights</h3>
        </div>
        <div className="prose prose-invert max-w-none">
          {loadingInsights ? (
            <div className="flex items-center gap-3">
              <div className="animate-spin rounded-full h-4 w-4 border-2 border-indigo-400 border-t-transparent"></div>
              <p className="text-indigo-200 italic">Gemini is analyzing your blood bank inventory...</p>
            </div>
          ) : (
            <p className="text-indigo-100 whitespace-pre-wrap leading-relaxed opacity-90">{insights}</p>
          )}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { InventoryItem, BloodType } from '../types';

interface InventoryProps {
  inventory: InventoryItem[];
  addStock: (type: BloodType, amount: number) => void;
  updateThreshold: (type: BloodType, threshold: number) => void;
  isAdmin: boolean;
}

const Inventory: React.FC<InventoryProps> = ({ inventory, addStock, updateThreshold, isAdmin }) => {
  const [selectedType, setSelectedType] = useState<BloodType>(BloodType.OPositive);
  const [amount, setAmount] = useState<number>(0);
  const [thresholdVal, setThresholdVal] = useState<number>(5000);

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (amount <= 0) return;
    addStock(selectedType, amount);
    setAmount(0);
  };

  const handleUpdateThreshold = (e: React.FormEvent) => {
    e.preventDefault();
    updateThreshold(selectedType, thresholdVal);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
      <div className="lg:col-span-2 space-y-4">
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-slate-50 border-b">
              <tr>
