import React, { useState, useEffect, useMemo } from 'react';
import { HashRouter, Routes, Route, Link, Navigate, useLocation } from 'react-router-dom';
import { 
  BloodType, User, UserRole, InventoryItem, Donor, 
  UsageLog, NotificationLog, StockHistory 
} from './types';
import { 
  INITIAL_USERS, INITIAL_INVENTORY, MOCK_DONORS, 
  HOSPITAL_LOCATION, BLOOD_COMPATIBILITY 
} from './constants';
import { geminiService } from './services/geminiService';
import { calculateDistance } from './utils/geoUtils';

// Components
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import Donors from './components/Donors';
import Usage from './components/Usage';
import Reports from './components/Reports';
import DonorOutreach from './components/DonorOutreach';
import Login from './components/Login';
import Sidebar from './components/Sidebar';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('currentUser');
    return saved ? JSON.parse(saved) : null;
  });

  const [inventory, setInventory] = useState<InventoryItem[]>(() => {
    const saved = localStorage.getItem('inventory');
    return saved ? JSON.parse(saved) : INITIAL_INVENTORY;
  });

  const [donors, setDonors] = useState<Donor[]>(() => {
    const saved = localStorage.getItem('donors');
    return saved ? JSON.parse(saved) : MOCK_DONORS;
  });

  const [usageLogs, setUsageLogs] = useState<UsageLog[]>(() => {
    const saved = localStorage.getItem('usageLogs');
    return saved ? JSON.parse(saved) : [];
  });

  const [notificationLogs, setNotificationLogs] = useState<NotificationLog[]>(() => {
    const saved = localStorage.getItem('notificationLogs');
    return saved ? JSON.parse(saved) : [];
  });

  // Persist state
  useEffect(() => {
    localStorage.setItem('inventory', JSON.stringify(inventory));
    localStorage.setItem('donors', JSON.stringify(donors));
    localStorage.setItem('usageLogs', JSON.stringify(usageLogs));
    localStorage.setItem('notificationLogs', JSON.stringify(notificationLogs));
    if (currentUser) {
      localStorage.setItem('currentUser', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('currentUser');
    }
  }, [inventory, donors, usageLogs, notificationLogs, currentUser]);

  const handleLogin = (user: User) => setCurrentUser(user);
  const handleLogout = () => setCurrentUser(null);

  const registerUsage = (type: BloodType, amount: number, patientId: string, customDate?: string) => {
    setInventory(prev => prev.map(item => {
      if (item.bloodType === type) {
        return { ...item, quantityMl: Math.max(0, item.quantityMl - amount), lastUpdated: new Date().toISOString() };
      }
      return item;
    }));

    const newLog: UsageLog = {
      id: `usage-${Date.now()}`,
      bloodType: type,
      quantityMl: amount,
      usageDate: customDate || new Date().toISOString(),
      patientId,
      staffId: currentUser?.name || currentUser?.id || 'unknown',
    };
    setUsageLogs(prev => [newLog, ...prev]);
  };

  const addStock = (type: BloodType, amount: number) => {
    setInventory(prev => prev.map(item => {
      if (item.bloodType === type) {
        return { ...item, quantityMl: item.quantityMl + amount, lastUpdated: new Date().toISOString() };
      }
      return item;
    }));
  };

  const updateThreshold = (type: BloodType, threshold: number) => {
    setInventory(prev => prev.map(item => {
      if (item.bloodType === type) {
        return { ...item, thresholdMl: threshold };
      }
      return item;
    }));
  };

  const initiateBroadcast = async (type: BloodType, targetDonors: Donor[]) => {
    const logs: NotificationLog[] = [];
    for (const donor of targetDonors) {
      const message = await geminiService.generateDonorSMS(donor.name, donor.bloodType, 'HIGH');
      const log: NotificationLog = {
        id: `notif-${Date.now()}-${donor.id}`,
        donorId: donor.id,
        donorName: donor.name,
        bloodType: type,
        message,
        sentDate: new Date().toISOString(),
        status: 'SENT',
      };
      logs.push(log);
    }
    setNotificationLogs(prev => [...logs, ...prev]);
  };

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <HashRouter>
      <div className="flex h-screen bg-slate-100 font-sans">
        <Sidebar role={currentUser.role} onLogout={handleLogout} />

        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          <header className="mb-8 flex justify-between items-center">
            <div>
              <h1 className="text-2xl font-bold text-slate-800 tracking-tight">HemaMatch</h1>
              <p className="text-slate-500 text-sm">Nairobi Referral Hospital Blood Bank Dashboard</p>
            </div>
            <div className="flex items-center gap-4">
              <span className="text-sm font-medium bg-white px-3 py-1 rounded-full shadow-sm border border-slate-200">
                {currentUser.name} ({currentUser.role})
              </span>
            </div>
          </header>

          <Routes>
            <Route path="/" element={
              <Dashboard 
                inventory={inventory} 
                usageLogs={usageLogs} 
                donors={donors} 
                onInitiateBroadcast={initiateBroadcast} 
              />
            } />
            <Route path="/inventory" element={<Inventory inventory={inventory} addStock={addStock} updateThreshold={updateThreshold} isAdmin={currentUser.role === UserRole.ADMIN} />} />
            <Route path="/donors" element={<Donors donors={donors} setDonors={setDonors} />} />
            <Route path="/outreach" element={<DonorOutreach inventory={inventory} donors={donors} notificationLogs={notificationLogs} onInitiateBroadcast={initiateBroadcast} />} />
            <Route path="/usage" element={<Usage inventory={inventory} registerUsage={registerUsage} currentStaffName={currentUser.name} />} />
            <Route path="/reports" element={<Reports usageLogs={usageLogs} notificationLogs={notificationLogs} />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { InventoryItem, Donor, BloodType, NotificationLog } from '../types';
import { calculateDistance } from '../utils/geoUtils';
import { HOSPITAL_LOCATION } from '../constants';
import { geminiService } from '../services/geminiService';

interface DonorOutreachProps {
  inventory: InventoryItem[];
  donors: Donor[];
  notificationLogs: NotificationLog[];
  onInitiateBroadcast: (type: BloodType, targetDonors: Donor[]) => Promise<void>;
}

const DonorOutreach: React.FC<DonorOutreachProps> = ({ inventory, donors, notificationLogs, onInitiateBroadcast }) => {
  const [selectedType, setSelectedType] = useState<BloodType | null>(null);
  const [loadingMsg, setLoadingMsg] = useState<string | null>(null);
  const [previews, setPreviews] = useState<Record<string, string>>({});

  const criticalTypes = useMemo(() => 
    inventory.filter(i => i.quantityMl < i.thresholdMl), 
    [inventory]
  );

  const getEligibleDonors = (type: BloodType) => {
    return donors.filter(d => {
      const dist = calculateDistance(HOSPITAL_LOCATION.lat, HOSPITAL_LOCATION.lng, d.lat, d.lng);
      const monthsSinceLast = (Date.now() - new Date(d.lastDonationDate).getTime()) / (1000 * 60 * 60 * 24 * 30);
      return d.bloodType === type && d.isSignedUp && dist <= 20 && monthsSinceLast > 3;
    });
  };

  const recentDispatch = useMemo(() => {
    if (!selectedType) return [];
    return notificationLogs
      .filter(log => log.bloodType === selectedType)
      .slice(0, 10);
  }, [notificationLogs, selectedType]);

  const handleGeneratePreviews = async () => {
    if (!selectedType) return;
    const targetDonors = getEligibleDonors(selectedType).slice(0, 3); // Preview first 3
    if (targetDonors.length === 0) {
      alert("No eligible donors found for this type within 20km.");
      return;
    }

    setLoadingMsg(`Generating AI message templates for ${selectedType} donors...`);
    const newPreviews: Record<string, string> = {};
    for (const donor of targetDonors) {
      const msg = await geminiService.generateDonorSMS(donor.name, donor.bloodType, 'HIGH');
      newPreviews[donor.id] = msg;
    }
    setPreviews(newPreviews);
    setLoadingMsg(null);
  };

  const handleBroadcast = async () => {
    if (!selectedType) return;
    const targetDonors = getEligibleDonors(selectedType);
    if (targetDonors.length === 0) {
      alert("No donors to broadcast to.");
      return;
    }
    setLoadingMsg(`Broadcasting messages to ${targetDonors.length} donors...`);
    await onInitiateBroadcast(selectedType, targetDonors);
    setLoadingMsg(null);
    setPreviews({});
    // Keep selection so user can see the status log update
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2 mb-4">
          <i className="fa-solid fa-tower-broadcast text-amber-500"></i>
          Emergency Outreach Center
        </h2>
        <p className="text-slate-500 text-sm mb-6">
          When blood levels drop below the threshold, use this section to coordinate with local donors via SMS. 
          Gemini AI will help craft persuasive messages based on urgency.
        </p>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          {criticalTypes.map(item => (
            <button
              key={item.bloodType}
              onClick={() => { setSelectedType(item.bloodType); setPreviews({}); }}
              className={`p-4 rounded-xl border-2 transition-all text-left ${
                selectedType === item.bloodType 
                  ? 'border-red-600 bg-red-50 ring-4 ring-red-50' 
                  : 'border-slate-100 bg-white hover:border-red-200'
              }`}
            >
              <div className="flex justify-between items-start mb-2">
                <span className="text-2xl font-black text-red-600">{item.bloodType}</span>
                <span className="bg-red-600 text-white text-[10px] font-bold px-1.5 py-0.5 rounded">CRITICAL</span>
              </div>
              <p className="text-xs font-bold text-slate-700">{item.quantityMl}ml Available</p>
              <p className="text-[10px] text-slate-400">Requires {item.thresholdMl}ml minimum</p>
            </button>
          ))}
          {criticalTypes.length === 0 && (
            <div className="col-span-full py-8 text-center bg-emerald-50 rounded-xl border border-emerald-100 text-emerald-700 font-medium">
              <i className="fa-solid fa-circle-check mr-2"></i>
              All blood levels are currently optimal. No outreach required.
            </div>
          )}
        </div>
      </div>

      {selectedType && (
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
          {/* ACTION PANEL */}
          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200">
            <div className="flex justify-between items-center mb-8 pb-4 border-b">
              <div>
                <h3 className="text-lg font-bold text-slate-800 tracking-tight">Recruitment Plan for {selectedType}</h3>
                <p className="text-sm text-slate-500">Targeting eligible donors within Nairobi (20km radius).</p>
              </div>
              <div className="text-right">
                <span className="block text-2xl font-bold text-slate-900">{getEligibleDonors(selectedType).length}</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase">Eligible Recipients</span>
              </div>
            </div>

            <div className="space-y-6">
              <div className="flex flex-col gap-3">
                <button 
                  onClick={handleGeneratePreviews}
                  disabled={!!loadingMsg}
                  className="w-full bg-slate-100 text-slate-700 font-bold py-3 rounded-xl hover:bg-slate-200 transition-colors flex items-center justify-center gap-2"
                >
                  <i className="fa-solid fa-wand-sparkles"></i>
                  {loadingMsg ? 'Processing...' : 'Generate AI Preview Templates'}
                </button>
                <button 
                  onClick={handleBroadcast}
                  disabled={!!loadingMsg}
                  className="w-full bg-red-600 text-white font-bold py-3 rounded-xl hover:bg-red-700 shadow-lg shadow-red-100 flex items-center justify-center gap-2 transition-all"
                >
                  <i className="fa-solid fa-paper-plane"></i>
                  {loadingMsg ? 'Broadcasting...' : `Broadcast to All ${selectedType} Donors`}
                </button>
              </div>

              {loadingMsg && (
                <div className="flex items-center justify-center gap-3 py-6">
                  <div className="animate-spin rounded-full h-5 w-5 border-2 border-amber-500 border-t-transparent"></div>
                  <p className="text-amber-600 font-medium italic text-sm">{loadingMsg}</p>
                </div>
              )}

              {!loadingMsg && Object.keys(previews).length > 0 && (
                <div className="space-y-4">
                  <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                    <i className="fa-solid fa-robot"></i>
                    AI Draft Previews
                  </h4>
                  {getEligibleDonors(selectedType).slice(0, 2).map(donor => (
                    <div key={donor.id} className="bg-slate-50 p-4 rounded-xl border border-slate-100">
                      <div className="flex justify-between mb-1">
                        <span className="text-xs font-bold text-slate-700">{donor.name}</span>
                        <span className="text-[10px] text-slate-400">{donor.phone}</span>
                      </div>
                      <p className="text-xs text-slate-600 leading-relaxed italic">
                        "{previews[donor.id]}"
                      </p>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          {/* STATUS PANEL */}
          <div className="bg-white p-8 rounded-2xl shadow-sm border border-slate-200 flex flex-col">
            <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
              <i className="fa-solid fa-clipboard-check text-emerald-500"></i>
              Dispatch Status Log
            </h3>

            <div className="flex-1 overflow-y-auto max-h-[400px] space-y-3 pr-2">
              {recentDispatch.map(log => (
                <div key={log.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-lg border border-slate-100">
                  <div className="flex flex-col">
                    <span className="text-sm font-bold text-slate-700">{log.donorName}</span>
                    <span className="text-[10px] text-slate-400">{new Date(log.sentDate).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })} dispatch</span>
                  </div>
                  <div className="text-right">
                    <span className={`text-[10px] font-bold px-2 py-1 rounded-full uppercase tracking-tighter ${
                      log.status === 'SENT' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                    }`}>
                      <i className={`fa-solid ${log.status === 'SENT' ? 'fa-check' : 'fa-clock'} mr-1`}></i>
                      {log.status}
                    </span>
                  </div>
                </div>
              ))}
              {recentDispatch.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-slate-300 py-10">
                  <i className="fa-solid fa-satellite-dish text-4xl mb-3 opacity-20"></i>
                  <p className="text-sm italic">Waiting for dispatch orders...</p>
                </div>
              )}
            </div>

            <div className="mt-6 pt-4 border-t border-slate-100 text-[10px] text-slate-400">
              <p><i className="fa-solid fa-circle-info mr-1"></i> Logs represent official SMS gateway triggers for the {selectedType} recruitment drive.</p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

