export const BLOOD_COMPATIBILITY: Record<BloodType, BloodType[]> = {
  [BloodType.APositive]: [BloodType.APositive, BloodType.ANegative, BloodType.OPositive, BloodType.ONegative],
  [BloodType.ANegative]: [BloodType.ANegative, BloodType.ONegative],
  [BloodType.BPositive]: [BloodType.BPositive, BloodType.BNegative, BloodType.OPositive, BloodType.ONegative],
  [BloodType.BNegative]: [BloodType.BNegative, BloodType.ONegative],
  [BloodType.ABPositive]: Object.values(BloodType), // Universal recipient
  [BloodType.ABNegative]: [BloodType.ABNegative, BloodType.ANegative, BloodType.BNegative, BloodType.ONegative],
  [BloodType.OPositive]: [BloodType.OPositive, BloodType.ONegative],
  [BloodType.ONegative]: [BloodType.ONegative], // Universal donor
};

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { 
  BloodType, User, UserRole, InventoryItem, Donor, 
  UsageLog, NotificationLog 
} from './types';
import { 
  INITIAL_INVENTORY, MOCK_DONORS, 
  HOSPITAL_LOCATION 
} from './constants';
import { calculateDistance } from './utils/geoUtils';

// Components
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import Donors from './components/Donors';
import Usage from './components/Usage';
import Reports from './components/Reports';
import DonorOutreach from './components/DonorOutreach';
import Login from './components/Login';
import Sidebar from './components/Sidebar';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('currentUser');
    return saved ? JSON.parse(saved) : null;
  });

  const [inventory, setInventory] = useState<InventoryItem[]>(() => {
    const saved = localStorage.getItem('inventory');
    return saved ? JSON.parse(saved) : INITIAL_INVENTORY;
  });

  const [donors, setDonors] = useState<Donor[]>(() => {
    const saved = localStorage.getItem('donors');
    return saved ? JSON.parse(saved) : MOCK_DONORS;
  });

  const [usageLogs, setUsageLogs] = useState<UsageLog[]>(() => {
    const saved = localStorage.getItem('usageLogs');
    return saved ? JSON.parse(saved) : [];
  });

  const [notificationLogs, setNotificationLogs] = useState<NotificationLog[]>(() => {
    const saved = localStorage.getItem('notificationLogs');
    return saved ? JSON.parse(saved) : [];
  });

  // Persist state
  useEffect(() => {
    localStorage.setItem('inventory', JSON.stringify(inventory));
    localStorage.setItem('donors', JSON.stringify(donors));
    localStorage.setItem('usageLogs', JSON.stringify(usageLogs));
    localStorage.setItem('notificationLogs', JSON.stringify(notificationLogs));
    if (currentUser) {
      localStorage.setItem('currentUser', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('currentUser');
    }
  }, [inventory, donors, usageLogs, notificationLogs, currentUser]);

  const handleLogin = (user: User) => setCurrentUser(user);
  const handleLogout = () => setCurrentUser(null);

  const registerUsage = (type: BloodType, amount: number, patientId: string, customDate?: string) => {
    setInventory(prev => prev.map(item => {
      if (item.bloodType === type) {
        return { ...item, quantityMl: Math.max(0, item.quantityMl - amount), lastUpdated: new Date().toISOString() };
      }
      return item;
    }));

    const newLog: UsageLog = {
      id: `usage-${Date.now()}`,
      bloodType: type,
      quantityMl: amount,
      usageDate: customDate || new Date().toISOString(),
      patientId,
      staffId: currentUser?.name || currentUser?.id || 'unknown',
    };
    setUsageLogs(prev => [newLog, ...prev]);
  };

  const addStock = (type: BloodType, amount: number) => {
    setInventory(prev => prev.map(item => {
      if (item.bloodType === type) {
        return { ...item, quantityMl: item.quantityMl + amount, lastUpdated: new Date().toISOString() };
      }
      return item;
    }));
  };

  const updateThreshold = (type: BloodType, threshold: number) => {
    setInventory(prev => prev.map(item => {
      if (item.bloodType === type) {
        return { ...item, thresholdMl: threshold };
      }
      return item;
    }));
  };

  const simulateResponse = (logId: string) => {
    const possibleResponses = [
      "I am on my way to the hospital now.",
      "I can come tomorrow morning at 9am.",
      "I donated recently elsewhere, sorry.",
      "I am currently unwell, maybe next month.",
      "Confirming I will be there in 30 minutes.",
      "Thank you for the alert, I'll be there."
    ];

    // Simulate network delay and reply
    setTimeout(() => {
      setNotificationLogs(prev => prev.map(log => {
        if (log.id === logId) {
          return {
            ...log,
            status: 'REPLIED',
            response: possibleResponses[Math.floor(Math.random() * possibleResponses.length)]
          };
        }
        return log;
      }));
    }, 3000 + Math.random() * 5000); // 3-8 seconds delay
  };

  const initiateBroadcast = async (type: BloodType, targetDonors: Donor[]) => {
    for (const donor of targetDonors) {
      // Small sequential delay to feel like a real broadcast
      await new Promise(resolve => setTimeout(resolve, 600));

      const logId = `notif-${Date.now()}-${donor.id}`;
      const log: NotificationLog = {
        id: logId,
        donorId: donor.id,
        donorName: donor.name,
        bloodType: type,
        message: `EMERGENCY ALERT: ${donor.name}, Nairobi Referral Hospital has a critical shortage of ${type} blood. Your previous donation helped save lives—we need you again today. Please reply to this message.`,
        sentDate: new Date().toISOString(),
        status: 'SENT',
      };

      setNotificationLogs(prev => [log, ...prev]);
      simulateResponse(logId);
    }
  };

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <HashRouter>
      <div className="flex h-screen bg-slate-100 font-sans">
        <Sidebar role={currentUser.role} onLogout={handleLogout} />

        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          <header className="mb-8 flex justify-between items-center">
            <div>
              <h1 className="text-2xl font-bold text-slate-800 tracking-tight">HemaMatch</h1>
              <p className="text-slate-500 text-sm">Nairobi Referral Hospital Blood Bank Dashboard</p>
            </div>
            <div className="flex items-center gap-4">
              <span className="text-sm font-medium bg-white px-3 py-1 rounded-full shadow-sm border border-slate-200">
                {currentUser.name} ({currentUser.role})
              </span>
            </div>
          </header>

          <Routes>
            <Route path="/" element={
              <Dashboard 
                inventory={inventory} 
                usageLogs={usageLogs} 
                donors={donors} 
                onInitiateBroadcast={initiateBroadcast} 
              />
            } />
            <Route path="/inventory" element={<Inventory inventory={inventory} addStock={addStock} updateThreshold={updateThreshold} isAdmin={currentUser.role === UserRole.ADMIN} />} />
            <Route path="/donors" element={<Donors donors={donors} setDonors={setDonors} />} />
            <Route path="/outreach" element={<DonorOutreach inventory={inventory} donors={donors} notificationLogs={notificationLogs} onInitiateBroadcast={initiateBroadcast} />} />
            <Route path="/usage" element={<Usage inventory={inventory} registerUsage={registerUsage} currentStaffName={currentUser.name} />} />
            <Route path="/reports" element={<Reports usageLogs={usageLogs} notificationLogs={notificationLogs} />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { InventoryItem, Donor, BloodType, NotificationLog } from '../types';
import { calculateDistance } from '../utils/geoUtils';
import { HOSPITAL_LOCATION } from '../constants';

interface DonorOutreachProps {
  inventory: InventoryItem[];
  donors: Donor[];
  notificationLogs: NotificationLog[];
  onInitiateBroadcast: (type: BloodType, targetDonors: Donor[]) => Promise<void>;
}

const DonorOutreach: React.FC<DonorOutreachProps> = ({ inventory, donors, notificationLogs, onInitiateBroadcast }) => {
  const [selectedType, setSelectedType] = useState<BloodType | null>(null);
  const [isBroadcasting, setIsBroadcasting] = useState(false);

  const criticalTypes = useMemo(() => 
    inventory.filter(i => i.quantityMl < i.thresholdMl), 
    [inventory]
  );

  const getEligibleDonors = (type: BloodType) => {
    return donors.filter(d => {
      const dist = calculateDistance(HOSPITAL_LOCATION.lat, HOSPITAL_LOCATION.lng, d.lat, d.lng);
      const monthsSinceLast = (Date.now() - new Date(d.lastDonationDate).getTime()) / (1000 * 60 * 60 * 24 * 30);
      return d.bloodType === type && d.isSignedUp && dist <= 25 && monthsSinceLast > 3;
    });
  };

  const recentDispatch = useMemo(() => {
    if (!selectedType) return [];
    return notificationLogs
      .filter(log => log.bloodType === selectedType)
      .slice(0, 15);
  }, [notificationLogs, selectedType]);

  const handleBroadcast = async () => {
    if (!selectedType) return;
    const targetDonors = getEligibleDonors(selectedType);
    if (targetDonors.length === 0) {
      alert("No eligible donors found for this type within 25km of the CBD.");
      return;
    }

    if (window.confirm(`Initiate emergency broadcast to ${targetDonors.length} donors? This will send real-time SMS alerts.`)) {
      setIsBroadcasting(true);
      await onInitiateBroadcast(selectedType, targetDonors);
      setIsBroadcasting(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2 mb-4">
          <i className="fa-solid fa-tower-broadcast text-red-500"></i>
          Emergency Outreach Center
        </h2>
        <p className="text-slate-500 text-sm mb-6">
          Direct messaging gateway for critical blood shortages. Choose a blood type below to start recruitment.
        </p>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
          {criticalTypes.map(item => (
            <button
              key={item.bloodType}
              onClick={() => setSelectedType(item.bloodType)}
              className={`p-4 rounded-xl border-2 transition-all text-left ${
                selectedType === item.bloodType 
                  ? 'border-red-600 bg-red-50 ring-4 ring-red-50' 
                  : 'border-slate-100 bg-white hover:border-red-200'
              }`}
            >
              <div className="flex justify-between items-start mb-2">
                <span className="text-2xl font-black text-red-600">{item.bloodType}</span>
                <span className="bg-red-600 text-white text-[10px] font-bold px-1.5 py-0.5 rounded animate-pulse">LOW STOCK</span>
              </div>
              <p className="text-xs font-bold text-slate-700">{item.quantityMl.toLocaleString()}ml Available</p>
              <p className="text-[10px] text-slate-400">Min Threshold: {item.thresholdMl.toLocaleString()}ml</p>
            </button>
          ))}
          {criticalTypes.length === 0 && (
            <div className="col-span-full py-12 text-center bg-emerald-50 rounded-xl border border-emerald-100">
              <i className="fa-solid fa-circle-check text-3xl text-emerald-500 mb-3 block"></i>
              <h3 className="text-emerald-800 font-bold">Inventory levels are stable.</h3>
              <p className="text-emerald-600 text-sm">No recruitment drive is currently necessary.</p>
            </div>
          )}
        </div>
      </div>

      {selectedType && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 animate-in fade-in slide-in-from-bottom-4 duration-300">
          {/* CONTROL PANEL */}
          <div className="lg:col-span-1 bg-white p-8 rounded-2xl shadow-sm border border-slate-200 h-fit">
            <h3 className="text-lg font-bold text-slate-800 mb-2">Dispatch Control</h3>
            <p className="text-sm text-slate-500 mb-6">Targeting donors for {selectedType} blood types.</p>

            <div className="bg-slate-50 p-5 rounded-xl border border-slate-100 mb-8">
              <div className="flex justify-between items-end mb-4">
                <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">Eligible Pool</span>
                <span className="text-2xl font-black text-slate-900">{getEligibleDonors(selectedType).length}</span>
              </div>
              <div className="space-y-3 text-xs text-slate-600">
                <div className="flex items-center gap-2">
                  <i className="fa-solid fa-location-dot text-blue-500"></i>
                  Nairobi County (25km Radius)
                </div>
                <div className="flex items-center gap-2">
                  <i className="fa-solid fa-clock text-emerald-500"></i>
                  Last donation > 3 months ago
                </div>
              </div>
            </div>

            <button 
              onClick={handleBroadcast}
              disabled={isBroadcasting || getEligibleDonors(selectedType).length === 0}
              className={`w-full font-bold py-4 rounded-xl transition-all shadow-lg flex items-center justify-center gap-3 ${
                isBroadcasting || getEligibleDonors(selectedType).length === 0
                  ? 'bg-slate-200 text-slate-400 cursor-not-allowed shadow-none'
                  : 'bg-red-600 text-white hover:bg-slate-900 shadow-red-100'
              }`}
            >
              {isBroadcasting ? (
                <>
                  <i className="fa-solid fa-satellite-dish animate-pulse"></i>
                  Dispatching Messages...
                </>
              ) : (
                <>
                  <i className="fa-solid fa-paper-plane"></i>
                  Launch Recruitment Drive
                </>
              )}
            </button>
            <p className="mt-4 text-[10px] text-slate-400 text-center font-medium">
              Manual SMS Broadcast Gateway • Secure Connection Active
            </p>
          </div>

          {/* MONITOR PANEL */}
          <div className="lg:col-span-2 bg-white rounded-2xl shadow-sm border border-slate-200 flex flex-col min-h-[500px]">
            <div className="p-6 border-b border-slate-100 flex justify-between items-center">
              <h3 className="font-bold text-slate-800 flex items-center gap-2">
                <i className="fa-solid fa-message text-blue-500"></i>
                Real-Time Message Status
              </h3>
            </div>

            <div className="flex-1 overflow-y-auto max-h-[600px] p-6 space-y-4">
              {recentDispatch.map(log => (
                <div 
                  key={log.id} 
                  className={`p-4 rounded-xl border transition-all ${
                    log.status === 'REPLIED' 
                      ? 'bg-emerald-50 border-emerald-100 shadow-sm' 
                      : 'bg-white border-slate-100'
                  }`}
                >
                  <div className="flex justify-between items-start mb-2">
                    <div className="flex items-center gap-3">
                      <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold ${
                        log.status === 'REPLIED' ? 'bg-emerald-600 text-white' : 'bg-slate-100 text-slate-500'
                      }`}>
                        {log.donorName.charAt(0)}
                      </div>
                      <div>
                        <p className="font-bold text-slate-800 text-sm mb-0.5">{log.donorName}</p>
                        <p className="text-[10px] text-slate-400">
                          {new Date(log.sentDate).toLocaleTimeString()}
                        </p>
                      </div>
                    </div>
                    <span className={`text-[10px] font-black px-2.5 py-1 rounded-full uppercase tracking-tighter ${
                      log.status === 'REPLIED' ? 'bg-emerald-600 text-white' : 'bg-blue-100 text-blue-700'
                    }`}>
                      {log.status === 'REPLIED' ? '✓ Received Reply' : 'Dispatching...'}
                    </span>
                  </div>

                  {log.status === 'REPLIED' && (
                    <div className="mt-3 pl-13">
                      <div className="bg-white border border-emerald-200 p-3 rounded-lg text-sm text-emerald-900 relative">
                        <i className="fa-solid fa-quote-left absolute -top-2 left-2 text-emerald-200 opacity-50"></i>
                        {log.response}
                      </div>
                    </div>
                  )}
                </div>
              ))}

              {recentDispatch.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-slate-300 py-20">
                  <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mb-4 border-2 border-dashed border-slate-200">
                    <i className="fa-solid fa-paper-plane text-2xl opacity-20"></i>
                  </div>
                  <p className="text-sm font-medium">No messages currently in the log.</p>
                  <p className="text-[10px] uppercase tracking-widest mt-1">Select a type and broadcast to see logs</p>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default DonorOutreach;

