import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { 
  BloodType, User, UserRole, InventoryItem, Donor, 
  UsageLog, NotificationLog 
} from './types';
import { 
  INITIAL_INVENTORY, MOCK_DONORS, 
  HOSPITAL_LOCATION, INITIAL_USERS 
} from './constants';
import { calculateDistance } from './utils/geoUtils';

// Components
import Dashboard from './components/Dashboard';
import Inventory from './components/Inventory';
import Donors from './components/Donors';
import Usage from './components/Usage';
import Reports from './components/Reports';
import DonorOutreach from './components/DonorOutreach';
import Login from './components/Login';
import Sidebar from './components/Sidebar';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('currentUser');
    return saved ? JSON.parse(saved) : null;
  });

  const [inventory, setInventory] = useState<InventoryItem[]>(() => {
    const saved = localStorage.getItem('inventory');
    return saved ? JSON.parse(saved) : INITIAL_INVENTORY;
  });

  const [donors, setDonors] = useState<Donor[]>(() => {
    const saved = localStorage.getItem('donors');
    return saved ? JSON.parse(saved) : MOCK_DONORS;
  });

  const [usageLogs, setUsageLogs] = useState<UsageLog[]>(() => {
    const saved = localStorage.getItem('usageLogs');
    return saved ? JSON.parse(saved) : [];
  });

  const [notificationLogs, setNotificationLogs] = useState<NotificationLog[]>(() => {
    const saved = localStorage.getItem('notificationLogs');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('inventory', JSON.stringify(inventory));
    localStorage.setItem('donors', JSON.stringify(donors));
    localStorage.setItem('usageLogs', JSON.stringify(usageLogs));
    localStorage.setItem('notificationLogs', JSON.stringify(notificationLogs));
    if (currentUser) {
      localStorage.setItem('currentUser', JSON.stringify(currentUser));
    } else {
      localStorage.removeItem('currentUser');
    }
  }, [inventory, donors, usageLogs, notificationLogs, currentUser]);

  const handleLogin = (user: User) => setCurrentUser(user);
  const handleLogout = () => setCurrentUser(null);

  const registerUsage = (type: BloodType, amount: number, patientId: string, customDate: string) => {
    setInventory(prev => prev.map(item => {
      if (item.bloodType === type) {
        return { ...item, quantityMl: Math.max(0, item.quantityMl - amount), lastUpdated: new Date().toISOString() };
      }
      return item;
    }));

    const newLog: UsageLog = {
      id: `usage-${Date.now()}`,
      bloodType: type,
      quantityMl: amount,
      usageDate: customDate,
      patientId,
      staffId: currentUser?.name || 'Unknown Staff',
    };
    setUsageLogs(prev => [newLog, ...prev]);
  };

  const addStock = (type: BloodType, amount: number) => {
    setInventory(prev => prev.map(item => {
      if (item.bloodType === type) {
        return { ...item, quantityMl: item.quantityMl + amount, lastUpdated: new Date().toISOString() };
      }
      return item;
    }));
  };

  const updateThreshold = (type: BloodType, threshold: number) => {
    setInventory(prev => prev.map(item => {
      if (item.bloodType === type) {
        return { ...item, thresholdMl: threshold };
      }
      return item;
    }));
  };

  const simulateResponse = (logId: string) => {
    const responses = [
      "I am near Westlands, I can come in 1 hour.",
      "Confirmed. I will visit the hospital tomorrow morning.",
      "I'm on my way now. See you soon.",
      "Sorry, I am out of Nairobi today.",
      "Thank you for the alert. I will be there by noon.",
    ];

    setTimeout(() => {
      setNotificationLogs(prev => prev.map(log => {
        if (log.id === logId) {
          return {
            ...log,
            status: 'REPLIED',
            response: responses[Math.floor(Math.random() * responses.length)]
          };
        }
        return log;
      }));
    }, 4000 + Math.random() * 6000);
  };

  const initiateBroadcast = async (type: BloodType, targetDonors: Donor[]) => {
    for (const donor of targetDonors) {
      await new Promise(resolve => setTimeout(resolve, 800)); // Simulated network latency

      const logId = `notif-${Date.now()}-${donor.id}`;
      const log: NotificationLog = {
        id: logId,
        donorId: donor.id,
        donorName: donor.name,
        bloodType: type,
        message: `EMERGENCY ALERT: ${donor.name}, Nairobi Referral Hospital has a critical shortage of ${type} blood. Your donation is needed urgently. Please visit the bank as soon as possible.`,
        sentDate: new Date().toISOString(),
        status: 'SENT',
      };

      setNotificationLogs(prev => [log, ...prev]);
      simulateResponse(logId);
    }
  };

  if (!currentUser) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <HashRouter>
      <div className="flex h-screen bg-slate-100 font-sans">
        <Sidebar role={currentUser.role} onLogout={handleLogout} />

        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          <header className="mb-8 flex justify-between items-center">
            <div>
              <h1 className="text-2xl font-bold text-slate-800 tracking-tight">HemaMatch</h1>
              <p className="text-slate-500 text-sm">Official Blood Bank System • {HOSPITAL_LOCATION.name}</p>
            </div>
            <div className="flex items-center gap-4">
              <span className="text-sm font-bold bg-white px-4 py-2 rounded-xl shadow-sm border border-slate-200 text-slate-700">
                <i className="fa-solid fa-user-md mr-2 text-red-500"></i>
                {currentUser.name}
              </span>
            </div>
          </header>

          <Routes>
            <Route path="/" element={
              <Dashboard 
                inventory={inventory} 
                usageLogs={usageLogs} 
                donors={donors} 
                onInitiateBroadcast={initiateBroadcast} 
              />
            } />
            <Route path="/inventory" element={<Inventory inventory={inventory} addStock={addStock} updateThreshold={updateThreshold} isAdmin={currentUser.role === UserRole.ADMIN} />} />
            <Route path="/donors" element={<Donors donors={donors} setDonors={setDonors} isAdmin={currentUser.role === UserRole.ADMIN} />} />
            <Route path="/outreach" element={<DonorOutreach inventory={inventory} donors={donors} notificationLogs={notificationLogs} onInitiateBroadcast={initiateBroadcast} />} />
            <Route path="/usage" element={<Usage inventory={inventory} registerUsage={registerUsage} currentStaffName={currentUser.name} />} />
            <Route path="/reports" element={<Reports usageLogs={usageLogs} notificationLogs={notificationLogs} />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { InventoryItem, Donor, BloodType, NotificationLog } from '../types';
import { calculateDistance } from '../utils/geoUtils';
import { HOSPITAL_LOCATION } from '../constants';

interface DonorOutreachProps {
  inventory: InventoryItem[];
  donors: Donor[];
  notificationLogs: NotificationLog[];
  onInitiateBroadcast: (type: BloodType, targetDonors: Donor[]) => Promise<void>;
}

const DonorOutreach: React.FC<DonorOutreachProps> = ({ inventory, donors, notificationLogs, onInitiateBroadcast }) => {
  const [selectedType, setSelectedType] = useState<BloodType | null>(null);
  const [isBroadcasting, setIsBroadcasting] = useState(false);

  const criticalTypes = useMemo(() => 
    inventory.filter(i => i.quantityMl < i.thresholdMl), 
    [inventory]
  );

  const getEligibleDonors = (type: BloodType) => {
    return donors.filter(d => {
      const dist = calculateDistance(HOSPITAL_LOCATION.lat, HOSPITAL_LOCATION.lng, d.lat, d.lng);
      const monthsSinceLast = (Date.now() - new Date(d.lastDonationDate).getTime()) / (1000 * 60 * 60 * 24 * 30);
      // Filter: <10km, signed up, eligible time (>3 months), correct type
      return d.bloodType === type && d.isSignedUp && dist <= 10 && monthsSinceLast > 3;
    });
  };

  const handleBroadcast = async () => {
    if (!selectedType) return;
    const targets = getEligibleDonors(selectedType);
    if (targets.length === 0) {
      alert(`No eligible ${selectedType} donors found within 10km of the hospital.`);
      return;
    }

    if (window.confirm(`Launch SMS alert to ${targets.length} donors?`)) {
      setIsBroadcasting(true);
      await onInitiateBroadcast(selectedType, targets);
      setIsBroadcasting(false);
    }
  };

  const recentLogs = useMemo(() => {
    if (!selectedType) return [];
    return notificationLogs.filter(l => l.bloodType === selectedType).slice(0, 10);
  }, [notificationLogs, selectedType]);

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
        <h2 className="text-xl font-bold text-slate-800 flex items-center gap-2 mb-4">
          <i className="fa-solid fa-tower-broadcast text-red-600"></i>
          Emergency Outreach Center
        </h2>
        <p className="text-slate-500 text-sm mb-6">
          Critical stock detected. Select a blood type to initiate recruitment of local donors within 10km.
        </p>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          {criticalTypes.map(item => (
            <button
              key={item.bloodType}
              onClick={() => setSelectedType(item.bloodType)}
              className={`p-4 rounded-xl border-2 text-left transition-all ${
                selectedType === item.bloodType 
                  ? 'border-red-600 bg-red-50 ring-4 ring-red-50' 
                  : 'border-slate-100 bg-white hover:border-red-200'
              }`}
            >
              <div className="flex justify-between items-center mb-1">
                <span className="text-2xl font-black text-red-600">{item.bloodType}</span>
                <span className="text-[10px] font-bold bg-red-600 text-white px-1.5 py-0.5 rounded">LOW</span>
              </div>
              <p className="text-xs font-bold text-slate-700">{item.quantityMl}ml Stock</p>
            </button>
          ))}
          {criticalTypes.length === 0 && (
            <div className="col-span-full py-6 text-center bg-emerald-50 text-emerald-700 rounded-xl font-medium border border-emerald-100">
              <i className="fa-solid fa-check-circle mr-2"></i>
              No emergency recruitment required. Stock levels healthy.
            </div>
          )}
        </div>
      </div>

      {selectedType && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 animate-in slide-in-from-bottom-4 duration-300">
          <div className="lg:col-span-1 bg-white p-6 rounded-2xl shadow-sm border border-slate-200 flex flex-col justify-between">
            <div>
              <h3 className="text-lg font-bold text-slate-800 mb-4">Broadcast Recruitment</h3>
              <div className="bg-slate-50 p-4 rounded-xl space-y-3 mb-6">
                <div className="flex justify-between text-sm">
                  <span className="text-slate-500">Local Pool (10km)</span>
                  <span className="font-bold text-slate-900">{getEligibleDonors(selectedType).length} donors</span>
                </div>
                <div className="flex justify-between text-sm">
                  <span className="text-slate-500">Estimated Cost</span>
                  <span className="font-bold text-emerald-600">KES 0.00 (System Mock)</span>
                </div>
              </div>
            </div>

            <button 
              onClick={handleBroadcast}
              disabled={isBroadcasting || getEligibleDonors(selectedType).length === 0}
              className={`w-full py-4 rounded-xl font-bold flex items-center justify-center gap-3 transition-all ${
                isBroadcasting 
                  ? 'bg-slate-100 text-slate-400' 
                  : 'bg-red-600 text-white hover:bg-slate-900 shadow-lg shadow-red-100'
              }`}
            >
              {isBroadcasting ? (
                <>
                  <i className="fa-solid fa-circle-notch animate-spin"></i>
                  Sending SMS...
                </>
              ) : (
                <>
                  <i className="fa-solid fa-paper-plane"></i>
                  Dispatch emergency SMS
                </>
              )}
            </button>
          </div>

          <div className="lg:col-span-2 bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
            <div className="p-4 bg-slate-50 border-b font-bold text-slate-700 flex justify-between items-center">
              <span>Live Response Tracking: {selectedType}</span>
              <span className="text-[10px] text-slate-400 uppercase tracking-widest">Nairobi Gateway 1</span>
            </div>

            <div className="flex-1 overflow-y-auto max-h-[400px] p-6 space-y-4">
              {recentLogs.map(log => (
                <div key={log.id} className={`p-4 rounded-xl border transition-all ${log.status === 'REPLIED' ? 'bg-emerald-50 border-emerald-100' : 'bg-white border-slate-100'}`}>
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-sm font-bold text-slate-800">{log.donorName}</span>
                    <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${log.status === 'REPLIED' ? 'bg-emerald-200 text-emerald-800' : 'bg-blue-100 text-blue-800'}`}>
                      {log.status === 'REPLIED' ? '✓ REPLIED' : '• SENT'}
                    </span>
                  </div>
                  {log.status === 'REPLIED' ? (
                    <div className="pl-4 border-l-2 border-emerald-300 italic text-sm text-emerald-900">
                      "{log.response}"
                    </div>
                  ) : (
                    <p className="text-xs text-slate-400">Awaiting donor response...</p>
                  )}
                </div>
              ))}
              {recentLogs.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-slate-300 py-12">
                  <i className="fa-solid fa-satellite-dish text-4xl mb-4 opacity-10"></i>
                  <p className="text-sm italic">No recent dispatch for {selectedType}</p>
                </div>
              )}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default DonorOutreach;

import React, { useState, useMemo } from 'react';
import { Donor, BloodType } from '../types';
import { calculateDistance } from '../utils/geoUtils';
import { HOSPITAL_LOCATION } from '../constants';

interface DonorsProps {
  donors: Donor[];
  setDonors: React.Dispatch<React.SetStateAction<Donor[]>>;
  isAdmin: boolean;
}

const Donors: React.FC<DonorsProps> = ({ donors, setDonors, isAdmin }) => {
  const [filterType, setFilterType] = useState<string>('ALL');
  const [maxDist, setMaxDist] = useState<number>(10);
  const [search, setSearch] = useState('');

  const filtered = useMemo(() => {
    return donors.filter(d => {
      const dist = calculateDistance(HOSPITAL_LOCATION.lat, HOSPITAL_LOCATION.lng, d.lat, d.lng);
      const matchesType = filterType === 'ALL' || d.bloodType === filterType;
      const matchesSearch = d.name.toLowerCase().includes(search.toLowerCase());
      const matchesDist = dist <= maxDist;
      return matchesType && matchesSearch && matchesDist;
    }).sort((a, b) => {
      const distA = calculateDistance(HOSPITAL_LOCATION.lat, HOSPITAL_LOCATION.lng, a.lat, a.lng);
      const distB = calculateDistance(HOSPITAL_LOCATION.lat, HOSPITAL_LOCATION.lng, b.lat, b.lng);
      return distA - distB;
    });
  }, [donors, filterType, maxDist, search]);

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 flex flex-wrap gap-6 items-end">
        <div className="flex-1 min-w-[200px]">
          <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Search Nairobi Donors</label>
          <div className="relative">
            <i className="fa-solid fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-400"></i>
            <input 
              type="text" 
              placeholder="Filter by name..." 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full bg-slate-50 border border-slate-100 rounded-xl pl-12 pr-4 py-3 outline-none focus:border-red-500"
            />
          </div>
        </div>

        <div>
          <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Blood Type</label>
          <select 
            value={filterType} 
            onChange={(e) => setFilterType(e.target.value)}
            className="bg-slate-50 border border-slate-100 rounded-xl px-4 py-3 outline-none focus:border-red-500 font-bold"
          >
            <option value="ALL">All Types</option>
            {Object.values(BloodType).map(t => <option key={t} value={t}>{t}</option>)}
          </select>
        </div>

        <div>
          <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Radius: {maxDist}km</label>
          <input 
            type="range" 
            min="1" 
            max="50" 
            value={maxDist} 
            onChange={(e) => setMaxDist(Number(e.target.value))}
            className="h-2 w-32 bg-slate-100 rounded-lg appearance-none cursor-pointer accent-red-600"
          />
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <table className="w-full text-left">
          <thead className="bg-slate-50 border-b text-[10px] font-bold text-slate-400 uppercase">
            <tr>
              <th className="px-6 py-4">Donor Profile</th>
              <th className="px-6 py-4">Type</th>
              <th className="px-6 py-4">Proximity</th>
              <th className="px-6 py-4">Last Donation</th>
              <th className="px-6 py-4">Status</th>
            </tr>
          </thead>
          <tbody className="divide-y text-sm">
            {filtered.map(d => {
              const dist = calculateDistance(HOSPITAL_LOCATION.lat, HOSPITAL_LOCATION.lng, d.lat, d.lng);
              return (
                <tr key={d.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <p className="font-bold text-slate-800">{d.name}</p>
                    <p className="text-xs text-slate-400">{d.phone} • {d.address}</p>
                  </td>
                  <td className="px-6 py-4 font-black text-red-600">{d.bloodType}</td>
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded-lg font-bold text-[10px] ${dist <= 10 ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-600'}`}>
                      {dist.toFixed(1)} km
                    </span>
                  </td>
                  <td className="px-6 py-4 text-slate-500">{d.lastDonationDate}</td>
                  <td className="px-6 py-4">
                    <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full ${d.isSignedUp ? 'bg-blue-50 text-blue-600' : 'bg-slate-100 text-slate-400'}`}>
                      {d.isSignedUp ? 'SMS ALERT ON' : 'OPT-OUT'}
                    </span>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
        {filtered.length === 0 && (
          <div className="p-12 text-center text-slate-400 italic">No donors found in this radius.</div>
        )}
      </div>
    </div>
  );
};

export default Donors;

